// Body aceito (Card React):
// 1) QTD-POR-LOTE (PREFERIDO): { deal_id, item_fpb: [{item_code, lotes: [{fpb_name, qty}]}] }
//    Operador aloca X ampolas lote 1, Y ampolas lote 2 por item.
//    Sistema distribui PACIENTES entre lotes (bin-pack). Receita = 1 lote inteiro.
// 2) PER-ITEM: { deal_id, fpb_map: { item_code: fpb_name } } — 1 lote pra todo item.
// 3) LEGACY: { deal_id, fpb_name } — 1 lote pra todos items.
const body = $input.first().json.body || $input.first().json;
const itemFpb = Array.isArray(body.item_fpb) ? body.item_fpb : null;
let fpbMap = body.fpb_map || null;
if (!fpbMap && Array.isArray(body.items) && !itemFpb) {
  fpbMap = {};
  for (const it of body.items) {
    if (it.item_code && it.fpb_name) fpbMap[it.item_code] = it.fpb_name;
  }
  if (!Object.keys(fpbMap).length) fpbMap = null;
}
return [{ json: {
  deal_id:   body.deal_id  || null,
  order_id:  body.order_id || null,
  fpb_name:  body.fpb_name || body.future_production_batch || null,
  fpb_map:   fpbMap,
  item_fpb:  itemFpb,
} }];

// Transforma dados Postgres em payload pra future_production_issue_order
const row = $input.first().json;
const order = row.order_data;
const comp = row.company || {};
const ct = row.contact || {};
const pay = row.payment || {};
const payer = row.payer || {};
const products = row.products || [];

if (!order) {
  return [{ json: { error: 'order não encontrado' } }];
}

// CPF/CNPJ priorize cpf_responsavel (PF Volpi) senão cnpj senão payer.cpf_cnpj
const taxId = (comp.cpf_responsavel || comp.cnpj || payer.cpf_cnpj || '').replace(/\D/g, '');
const isCompany = !!comp.cnpj && (comp.cnpj || '').replace(/\D/g, '').length === 14;

// Customer
const customer = {
  customer_name: comp.name || payer.name || order.company_name || 'Sem Nome',
  customer_type: isCompany ? 'Company' : 'Individual',
  customer_group: 'Volpi',
  territory: 'Brazil',
  tax_id: taxId,
  address: (payer.address || comp.endereco) ? {
    title: comp.name || payer.name,
    type: 'Billing',
    address_line1: payer.address || comp.endereco || '',
    address_line2: payer.complement || comp.complemento || '',
    city: comp.municipio || (payer.city || ''),
    state: comp.uf || comp.estado_conselho || (payer.province || ''),
    pincode: comp.cep || payer.postal_code || '',
    country: 'Brazil',
    email_id: ct.email || payer.email || '',
    phone: ct.phone || payer.phone || '',
  } : null,
  contact: ct.firstname ? {
    first_name: ct.firstname,
    last_name: ct.lastname || '',
    email: ct.email || '',
    phone: ct.phone || '',
  } : null,
};

// Prescribers — médico responsável técnico da company + médicos únicos dos pacientes
const presMap = new Map();
if (comp.nome_responsavel_tecnico && comp.numero_conselho) {
  const consec = (comp.conselho || '').replace(/^\d+\s*-\s*/, '') || 'CRM';
  const key = `${comp.cpf_responsavel || ''}|${consec}|${comp.numero_conselho}|${comp.estado_conselho || comp.uf || ''}`;
  presMap.set(key, {
    cpf: (comp.cpf_responsavel || '').replace(/\D/g, ''),
    full_name: comp.nome_responsavel_tecnico,
    councils: [{
      council_type: consec,
      council_number: String(comp.numero_conselho),
      council_state: comp.estado_conselho || comp.uf || '',
      is_primary: 1,
    }],
  });
}
for (const prod of products) {
  for (const item of (prod.patients || [])) {
    const p = item.patient;
    if (!p.medico_crm) continue;
    const key = `||CRM|${p.medico_crm}|${p.medico_uf}`;
    if (presMap.has(key)) continue;
    presMap.set(key, {
      cpf: '',
      full_name: p.medico_nome,
      councils: [{ council_type: 'CRM', council_number: String(p.medico_crm), council_state: p.medico_uf, is_primary: 1 }],
    });
  }
}
const prescribers = Array.from(presMap.values());

// Patients (únicos por CPF)
const patMap = new Map();
for (const prod of products) {
  for (const item of (prod.patients || [])) {
    const p = item.patient;
    const cpfd = (p.cpf || '').replace(/\D/g, '');
    if (!cpfd || patMap.has(cpfd)) continue;
    patMap.set(cpfd, {
      cpf: cpfd,
      patient_name: p.nome,
      mobile: p.telefone || '',
      gender: 'Outro',
      default_prescriber_cpf: '',  // será resolvido pelo lookup CRM+UF
    });
  }
}
const patients = Array.from(patMap.values());

// Items (linhas do SO)
const items = [];
const fp_patients = [];
for (const prod of products) {
  items.push({
    item_code: prod.sku,
    qty: Number(prod.quantity),
    rate: Number(prod.price),
    warehouse: 'Produtos Acabados - I',
  });
  for (const item of (prod.patients || [])) {
    const p = item.patient;
    fp_patients.push({
      patient_cpf: (p.cpf || '').replace(/\D/g, ''),
      prescriber_cpf: '',
      prescriber_council: {
        council_type: 'CRM',
        council_number: String(p.medico_crm || ''),
        council_state: p.medico_uf || '',
      },
      item_code: prod.sku,
      qty: Number(p.quantidade),
    });
  }
}

// Adiciona FRETE se tiver no deal (n8n não busca line_items HubSpot, então TODO)
// Por agora deixa só os items do validacao_receita

// FPB explicito vindo do Card React (passa via Parse input)
const parsed = $('Parse input').first().json;
const fpbName = parsed.fpb_name;
const fpbMap = parsed.fpb_map;
const itemFpb = parsed.item_fpb;

const out = {
  hubspot: {
    deal_id: String(order.hubspot_deal_id || ''),
    contact_id: String(ct.hs_object_id || ''),
  },
  company: 'Injmedpharma',
  fpb_name: fpbName || null,
  fpb_map: fpbMap || null,
  item_fpb: itemFpb || null,
  customer,
  prescribers,
  patients,
  items,
  fp_patients,
  payment: pay.id ? {
    amount: pay.amount_cents ? Number(pay.amount_cents) / 100 : null,
    status: 'PAID',
    transaction_id: pay.id,
    paid_at: pay.paid_at,
  } : null,
  prescriptions: {
    count: products.reduce((s, p) => s + (p.patients || []).length, 0),
    reference: `validacao_receita order_id=${order.id}`,
  },
};

return [{ json: out }];
